var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그게 정말이야?!","JPN":"それ、本当！？","ENG":"Is that true?!","TWN":"你說的是真的？！"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"응! 새로 개발해낸 치료 방법인데, 박사님이 허락해 주셨어!","JPN":"うん！　新しく開発した治療方法だけど、博士が許可してくれた！","ENG":"Yeah! There's a newly developed treatment and the doctor approved it!","TWN":"嗯！這是新開發的治療方法，博士已經批准了！"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"그치만… 이 일에는 마브카의 힘이 필요하다고 생각해서….","JPN":"でも……これを試すにはマブカの力が必要だと思って……","ENG":"But... I think this will need Mavka's strength...","TWN":"但是……我覺得這件事需要瑪卡的力量……"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"빨리 말해줘! 내가 뭘 하면 되는데!","JPN":"早く話して！　何をすればいいの！","ENG":"Just tell me! What do I have to do?!","TWN":"快告訴我！我該怎麼做！"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"그, 그러니까….","JPN":"え、ええっと……","ENG":"S-so...","TWN":"就，就是……"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"히힛. 그건 내가 안내해 줄게.","JPN":"ひひっ。それは私が案内してあげる。","ENG":"Hehe. I'll tell you.","TWN":"嘻嘻，這個我來說吧。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"드, 드레카…!","JPN":"ド、ドレカ……！","ENG":"D-Dreka...!","TWN":"德，德蕾卡……！"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"언니도 참… 또 나만 빼놓고 친구랑 놀고 있던 거야?","JPN":"姉さんったら……また私を差し置いてお友だちと遊んでたの？","ENG":"Oh, sis... Were you playing with a friend without me?","TWN":"姊姊真是的……又把我丟下，自己和朋友玩？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"한참 동안 방에서 기다렸는데도 안 와주고… 너무 서운해.","JPN":"部屋でかなり待ってたのに来てくれないし……本当に悲しいじゃない。","ENG":"I was waiting in my room, but you never came... I'm so upset.","TWN":"我在房間裡等了好久你都沒來……太讓人失望了。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"그, 그렇지 않아! 곧 찾아갈 생각이었는데…!","JPN":"ち、違うよ！　すぐ行くつもりだったけど……！","ENG":"I-it's not like that! I was planning on going there soon–!","TWN":"不，不是這樣的！我本來打算馬上去找你的……！"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"히익…!","JPN":"ひいっ……！","ENG":"Eeek...!","TWN":"啊……！"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"응. 다 이해할 수 있어. 난 언니의 착한 동생이니까.","JPN":"うん。わかってるって、私は姉のいい妹だからね。","ENG":"Yeah. I understand. Because I'm your kind little sister.","TWN":"嗯，我能理解，因為我是姊姊的好妹妹嘛。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"그래도… 나도 마브카 언니와 친해지고 싶은데…","JPN":"でも……私もマブカさんと仲良くなりたいなあ……","ENG":"But... I also want to become friends with Mavka...","TWN":"可是……我也想和瑪卡姊姊做好朋友……"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"이야긴 전부 들었어. 내가 안내해 줄 테니까 따라와줘.","JPN":"話は全部聞いたよ。私が案内してあげるから、ついて来て。","ENG":"I heard everything. Follow me and I'll guide you.","TWN":"我全部都聽說了，我來帶路，你跟我來吧。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"히힛. 물론 에바 언니도 같이.","JPN":"ひひっ。もちろん姉さんもね。","ENG":"Hehe. You have to come along too, sis.","TWN":"嘻嘻，當然還有耶娃姊姊一起。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"여긴 설마…!","JPN":"ここは、まさか……！","ENG":"Is this...?!","TWN":"這裡難道是……！"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"그리운 장소지?","JPN":"懐かしい場所でしょう？","ENG":"Did you miss this place?","TWN":"是個讓人懷念的地方吧？"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"치, 침식체가 이렇게나 많이…!","JPN":"し、侵食体がこんなにたくさん……！","ENG":"Th-there are so many C.O.s...!","TWN":"侵，侵蝕體竟然這麼多……！"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"걱정하지마. 마브카 언니는 분명 잘 싸워줄 거야.","JPN":"心配はいらないよ。きっとマブカさんなら余裕で戦えるよ。","ENG":"Don't worry. I'm sure Mavka will take care of all of them.","TWN":"別擔心，瑪卡姊姊一定會好好戰鬥的。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"너희들 도대체 무슨 속셈이야…!","JPN":"あなたたち、いったいどういうつもりなの……！？","ENG":"What's all this for...?!","TWN":"你們到底有什麼企圖……！"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"히힛. 이건 말이지. 실험에 실패한…","JPN":"ひひっ。これはね。実験に失敗した……","ENG":"Hehe. Well, these are failed subjects–","TWN":"嘻嘻，這些呢，是實驗失敗的……"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그건 나도 알아!","JPN":"それは私もわかってる！","ENG":"I know that!","TWN":"這些我也知道！"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"지금 나더러… 이 아이들을 사냥시킬 생각인 거잖아!","JPN":"私に……この子どもたちを処理させるつもりでしょう！","ENG":"You want me... to hunt down all these kids!","TWN":"現在你是想讓我……去獵殺這些孩子們嗎！"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};